#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAX_POINTS 750000
#define MIN(a, b) ((a) < (b) ? (a) : (b))
#define MAX(a, b) ((a) > (b) ? (a) : (b))
typedef struct Point {
    int x, y;
} Point;
int compare(const void *a, const void *b) {
    Point *p1 = (Point *)a;
    Point *p2 = (Point *)b;
    if (p1->x == p2->x) return p1->y - p2->y;
    return p1->x - p2->x;
}
int orientation(Point p, Point q, Point r) {
    int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (val == 0) return 0; // collinear
    return (val > 0) ? 1 : 2; // clock or counterclock wise
}
int distance(Point p1, Point p2) {
    return (p1.x - p2.x) * (p1.x - p2.x) + (p1.y - p2.y) * (p1.y - p2.y);
}
void convexHull(Point points[], int n, Point hull[]) {
    int l = 0;
    for (int i = 1; i < n; i++)
        if (points[i].x < points[l].x)
            l = i;
    int p = l, q;
    do {
        hull[++hull[0].x] = points[p];
        q = (p + 1) % n;
        for (int i = 0; i < n; i++)
            if (orientation(points[p], points[i], points[q]) == 2)
                q = i;
        p = q;
    } while (p != l);
}
int main() {
    int n;
    scanf("%d", &n);
    Point points[n];
    for (int i = 0; i < n; i++)
        scanf("%d %d", &points[i].x, &points[i].y);
    Point hull[n];
    hull[0].x = -1;
    for (int i = 0; i < n; i++) {
        convexHull(points, i + 1, hull);
        int maxDist = 0;
        for (int j = 1; j <= hull[0].x; j++)
            for (int k = j + 1; k <= hull[0].x; k++)
                maxDist = MAX(maxDist, distance(hull[j], hull[k]));
        printf("%d\n", maxDist);
    }
    return 0;
}

