#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
using namespace std;
struct Point {
    int x, y;
};
bool compare(const Point &a, const Point &b) {
    if (a.x == b.x) return a.y < b.y;
    return a.x < b.x;
}
int orientation(const Point &p, const Point &q, const Point &r) {
    int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (val == 0) return 0; // collinear
    return (val > 0) ? 1 : 2; // clock or counterclock wise
}
int distance(const Point &p1, const Point &p2) {
    return (p1.x - p2.x) * (p1.x - p2.x) + (p1.y - p2.y) * (p1.y - p2.y);
}
vector<Point> convexHull(vector<Point> points) {
    int n = points.size();
    sort(points.begin(), points.end(), compare);
    vector<Point> hull;
    for (int i = 0; i < n; i++) {
        while (hull.size() >= 2 && orientation(hull[hull.size() - 2], hull[hull.size() - 1], points[i]) != 2)
            hull.pop_back();
        hull.push_back(points[i]);
    }
    return hull;
}
int main() {
    int n;
    cin >> n;
    vector<Point> points(n);
    for (int i = 0; i < n; i++)
        cin >> points[i].x >> points[i].y;
    for (int i = 0; i < n; i++) {
        vector<Point> hull = convexHull(vector<Point>(points.begin(), points.begin() + i + 1));
        int maxDist = 0;
        for (int j = 0; j < hull.size(); j++)
            for (int k = j + 1; k < hull.size(); k++)
                maxDist = max(maxDist, distance(hull[j], hull[k]));
        cout << maxDist << endl;
    }
    return 0;
}

