import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static class Point {
        int x, y;
        Point(int x, int y) {
            this.x = x;
            this.y = y;
        }
    }
    static int compare(Point a, Point b) {
        if (a.x == b.x) return a.y - b.y;
        return a.x - b.x;
    }
    static int orientation(Point p, Point q, Point r) {
        int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
        if (val == 0) return 0; // collinear
        return (val > 0) ? 1 : 2; // clock or counterclock wise
    }
    static int distance(Point p1, Point p2) {
        return (p1.x - p2.x) * (p1.x - p2.x) + (p1.y - p2.y) * (p1.y - p2.y);
    }
    static Point[] convexHull(Point[] points) {
        Arrays.sort(points, (a, b) -> compare(a, b));
        Point[] hull = new Point[points.length];
        int size = 0;
        for (Point p : points) {
            while (size >= 2 && orientation(hull[size - 2], hull[size - 1], p) != 2)
                size--;
            hull[size++] = p;
        }
        return hull;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        Point[] points = new Point[n];
        for (int i = 0; i < n; i++)
            points[i] = new Point(scanner.nextInt(), scanner.nextInt());
        for (int i = 0; i < n; i++) {
            Point[] hull = convexHull(Arrays.copyOfRange(points, 0, i + 1));
            int maxDist = 0;
            for (int j = 0; j < hull.length; j++)
                for (int k = j + 1; k < hull.length; k++)
                    maxDist = Math.max(maxDist, distance(hull[j], hull[k]));
            System.out.println(maxDist);
        }
    }
}

